            "NoDigitsHere",    // fails digit rule
            "ValidPass2024",   // passes both
            "12345678",        // passes both
            "abc"              // fails length
        };

        for (String p : testPasswords) {
            try {
                System.out.println("Testing: " + p);
                validatePassword(p);
            } catch (WeakPasswordException e) {
                System.out.println("WeakPasswordException: " + e.getMessage());
            }
        }
    }
}
