## 3.6 Complete Working Program: Event Demo

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class EventDemo extends JFrame implements ActionListener {
    private JTextField tf;
    private JButton b1, b2;
    private JLabel label;
    private int count = 0;

    public EventDemo() {
        setTitle("Event Handling Demo");
        setSize(400, 200);
        setLayout(new FlowLayout());
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        tf = new JTextField(15);
        b1 = new JButton("Click Me");
        b2 = new JButton("Reset");
        label = new JLabel("Counter: 0");

        // Pattern 1: 'this' class implements ActionListener
        b1.addActionListener(this);
        b2.addActionListener(this);

        // Pattern 3: Anonymous inner class
        tf.addActionListener(e -> tf.setText("Enter pressed!"));

        add(tf); add(b1); add(b2); add(label);
        setVisible(true);
    }

    @Override
    public void actionPerformed(ActionEvent e) {
        if (e.getSource() == b1) {
            count++;
            label.setText("Counter: " + count);
        } else if (e.getSource() == b2) {
            count = 0;
            label.setText("Counter: 0");
        }
    }

    public static void main(String[] args) {
        new EventDemo();
    }
}
```
